CREATE OR REPLACE FUNCTION OFSERM.DERIVATIVE_FORWARDS_EXPOSURE_DATA_POPULATION_ABL_CSTM(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DERIVATIVES(N_CLEARED_TXN_BANK_ROLE_ID,N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_D_CUST_INDUSTRY_SKEY,F_ILLIQUID_DERIVATIVES,F_OTC_IND,F_SOLVENCY_IND,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,N_ORIG_NETTING_AGREEMENT_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_CLEARED_TXN_COLLATERAL,F_COUNTERPARTY_CMC_FLAG,F_EXP_FOR_SALE_IND,F_INSTR_ULY_CCY_SAME_IND,F_INTERNAL_CUST_IND,F_NETTABILITY_FLAG,F_PARENT_FIDUCIARY_ACCT_IND,F_QUALIFIED_CCP_FLAG,F_REGULATORY_PARTY_INDICATOR,F_TREASURY_STOCK_INDICATOR,F_TRS_ASSET_OFFSETTING,N_CENTRAL_COUNTERPARTY_SKEY,N_CLEARING_MEMBER_SKEY,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_DVA_AMOUNT,N_EFFECTIVE_EXP_AMT,N_EL_AMOUNT,N_EXCHANGE_RATE,N_EXP_COVERED_AMT,N_EXP_MTM_VALUE,N_EXP_SENIORITY,N_EXP_UNCOVERED_AMT,N_GROUP_ASSET_SIZE,N_INCURRED_CVA_AMOUNT,N_LATEST_MATURITY,N_LOSS_ALLOWANCE_LIFE_ECL,N_MARGIN_AMOUNT,N_MARKET_VALUE,N_NETTING_AGREEMENT_SKEY,N_NOTIONAL_PRINCIPAL,N_ORIGINAL_MATURITY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_PRE_MITIGATION_EL_AMT,N_PRE_MITIGATION_RWA_EL,N_PROVISION_AMOUNT,N_REALISED_LGD,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_STRIKE_RATE_PRICE,N_TIME_TO_START,N_UNCOVERED_RWA_UL,N_UNDERLYING_FORWARD_PRICE,N_UNDERLYING_RESIDUAL_MATURITY,N_INSTR_VALUATION_ADJ_AMOUNT,N_WRITE_OFF_AMT,V_APPROACH_TYPE,V_EXP_RCY_CODE,V_UNDERLYING_DATA_IDENTIFIER,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,N_ADJUSTED_LGD_PERCENT,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_STD_COMMODITY_SKEY,N_INSTR_TYPE_SKEY,N_UNDERLYING_TYPE_SKEY,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_REG_INDUSTRY_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,N_RUN_PARAMETER_SETUP_SKEY,D_EXPOSUR