WARDS.F_CLEARED_TRANSACTION_FLAG,'N') ='Y' Then 'Y' end,CASE WHEN DIM_HOLDING_TYPE.V_HOLDING_TYPE = 'AFS' THEN 'Y' ELSE 'N' END,CASE WHEN STG_UNDERLYING_EXPOSURES.V_CCY_CODE = STG_FORWARDS.V_CCY_CODE THEN 'Y' ELSE 'N' END,CASE WHEN INTERNAL_ENTITY.N_ENTITY_SKEY IS NOT NULL AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR') THEN 'Y' ELSE 'N' END,CASE WHEN COALESCE(STG_FORWARDS.f_contract_walk_away_ind,'N') = 'Y' THEN 'N' ELSE STG_FORWARDS.f_nettability_flag END,CASE WHEN DIM_EXPOSURE_FIDUCIARY.N_ACCT_SKEY  IS NOT NULL THEN 'Y' ELSE 'N' END,DIM_PARTY_CCP.f_qualified_ccp_flag,DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,CASE WHEN FCT_ENTITY_INFO.V_PARTY_ID = STG_FORWARDS.V_CUST_REF_CODE THEN 'Y' ELSE 'N' END,STG_FORWARDS.F_TRS_ASSET_OFFSETTING,DIM_PARTY_CCP.n_party_skey,DIM_PARTY_CM.n_party_skey,0,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,COALESCE(STG_FORWARDS.N_DVA_AMOUNT,0) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_FORWARDS.N_EFFECTIVE_EXP_AMT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,STG_FORWARDS.N_MTM_VALUE /* FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*/,COALESCE(STG_FORWARDS.N_EXP_SENIORITY,1),0,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(STG_FORWARDS.N_INCURRED_CVA_AMOUNT,0) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,GREATEST((GREATEST(STG_FORWARDS.D_MATURITY_DATE, COALESCE(STG_UNDERLYING_DTL.D_MATURITY_DATE, STG_FORWARDS.D_MATURITY_DATE)) - STG_FORWARDS.FIC_MIS_DATE), 10) / 365 /*GREATEST(DAYS_BETWEEN(STG_FORWARDS.FIC_MIS_DATE, GREATEST(STG_FORWARDS.D_MATURITY_DATE, COALESCE(STG_UNDERLYING_DTL.D_MATURITY_DATE, STG_FORWARDS.D_MATURITY_DATE)), STG_FORWARDS.V_DAY_COUNT_IND), 10 / 365) */,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,STG_FORWARDS.N_MARGIN_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_FORWARDS.N_MARKET_VALUE /* FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*/,COALESCE(DIM_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, DUMMY_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY, 0),STG_FORWARDS.N_NOTIONAL_AMT/*(CASE WHEN  STG_FORWARDS.N_MV_PER_UNIT_RCY * STG_FORWARDS.N_CONTRACT_QUANTITY IS NULL THEN STG_FORWARDS.N_NOTIONAL_AMT  ELSE STG_FORWARDS.N_MV_PER_UNIT_RCY * STG_FORWARDS.N_CONTRACT_QUANTITY END) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*/,(STG_FORWARDS.D_MATURITY_DATE - STG_FORWARDS.D_CONTRACT_START_DATE)/365 /* DAYS_BETWEEN(STG_FORWARDS.D_CONTRACT_START_DATE,STG_FORWARDS.D_MATURITY_DATE,STG_FORWARDS.V_DAY_COUNT_IND) */,FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,0,0,STG_FORWARDS.N_PROVISION_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_FORWARDS.N_LGD_PERCENT_PRE_CRM,(STG_FORWARDS.D_MATURITY_DATE - DIM_DATES.D_CALENDAR_DATE)/365 /* DAYS_BETWEEN(DIM_DATES.D_CALENDAR_DATE,STG_FORWARDS.D_MATURITY_DATE,STG_FORWARDS.V_DAY_COUNT_IND) */,'870',0,0,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,STG_FORWARDS.N_STRIKE_RATE_PRICE  * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN STG_FORWARDS.FIC_MIS_DATE > LEAST(STG_FORWARDS.D_CONTRACT_START_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_FORWARDS.D_CONTRACT_START_DATE)) THEN 0 ELSE CASE WHEN DAYS_BETWEEN(STG_FORWARDS.FIC_MIS_DATE, LEAST(STG_FORWARDS.D_CONTRACT_START_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_FORWARDS.D_CONTRACT_START_DATE)), STG_FORWARDS.V_DAY_COUNT_IND) < 10 / 365 THEN 10 / 365 ELSE DAYS_BETWEEN(STG_FORWARDS.FIC_MIS_DATE, LEAST(STG_FORWARDS.D_CONTRACT_START_DATE, COALESCE(STG_UNDERLYING_DTL.D_EFFECTIVE_DATE,STG_FORWARDS.D_CONTRACT_START_DATE)), STG_FORWARDS.V_DAY_COUNT_IND) END END,0,STG_FORWARDS.N_UNDERLYING_FORWARD_PRICE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(STG_UNDERLYING_DTL.D_MATURITY_DATE -  STG_FORWARDS.FIC_MIS_DATE) / 365,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_FORWARDS.N_WRITE_OFF_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,FSI_CAP_RUN_EXE_PARAMETERS.V_RCY_CODE,NULL /*CHECK LATER*/,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_COMMODITY_CLASSIFICATION.N_STD_COMMODITY_SKEY),to_char(FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY),to_char(FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_UNDERLYING_TYPE_SKEY),to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_INDUSTRY_RECLASS.N_REG_INDUSTRY_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY),STG_FORWARDS.D_CONTRACT_START_DATE,STG_FORWARDS.D_MATURITY_DATE,STG_FORWARDS.F_ACCT_DEFAULTED_FLAG,STG_FORWARDS.F_AUTO_CANCELLATION_FLAG,STG_FORWARDS.F_BUYER_SELLER_IND,STG_FORWARDS.F_CAPITAL_MARKET_EXPOSURE,STG_FORWARDS.F_CLEARED_TRANSACTION_FLAG,STG_FORWARDS.F_CONTRACT_CANCELLED_IND,STG_FORWARDS.F_DVP_FLAG,STG_FORWARDS.F_EXEMPT_CAP_MARKET_EXP_IND,STG_FORWARDS.F_EXP_FUND_CCY_SAME_IND,STG_FORWARDS.F_EXP_FX_FUND_CURR_SAME_IND,STG_FORWARDS.F_EXP_HELD_AT_FAIR_VALUE,STG_FORWARDS.F_FAILED_TRADE_FLAG,STG_FORWARDS.F_GUAR_BY_SOVERIGN_IND,STG_FORWARDS.F_LONG_SETTLEMENT_TXN_FLAG,STG_FORWARDS.F_MARGINED_TXN_IND,STG_FORWARDS.F_MATERIALITY_FLAG,STG_FORWARDS.F_ONE_WAY_CASH_PAYMENT_IND,STG_FORWARDS.F_PAST_DUE_FLAG,STG_FORWARDS.F_RECIPROCAL_CROSS_HLDG_IND,STG_FORWARDS.F_REG_CAP_INVST_IND,STG_FORWARDS.F_SECURED_IND,STG_FORWARDS.F_SENIOR_CLAIM_FLAG,STG_FORWARDS.F_SHORT_POSITION_IND,STG_FORWARDS.F_SPECIFIC_WRONG_WAY_RISK_IND,STG_FORWARDS.F_SQUARED_POS_TRADE_IND,STG_FORWARDS.F_UNCOND_CANCELLED_EXP_IND,to_char(STG_FORWARDS.N_ACTUAL_BUSINESS_DAYS),to_char(STG_FORWARDS.N_BUSINESS_DAYS_LONG_TXN),to_char(STG_FORWARDS.N_CONTRACT_QUANTITY),to_char(STG_FORWARDS.N_DELINQUENT_DAYS),to_char(STG_FORWARDS.N_FAILED_BUSINESS_DAYS),to_char(STG_FORWARDS.N_HOLDING_PERIOD),to_char(STG_FORWARDS.N_INSTR_RESIDUAL_MATURITY),to_char(STG_FORWARDS.N_LOAD_RUN_ID),to_char(STG_FORWARDS.N_MIN_HOLDING_PERIOD),to_char(STG_FORWARDS.N_OTC_DERIVATIVE_MULTIPLIER),to_char(STG_FORWARDS.N_REMARGIN_FREQUENCY),to_char(STG_FORWARDS.N_SETTLEMENT_DAYS),to_char(STG_FORWARDS.N_STD_BUSINESS_DAYS),to_char(STG_FORWARDS.N_SUPERVISORY_BETA_VALUE),STG_FORWARDS.V_BOOK_TYPE,STG_FORWARDS.V_CCY_CODE,STG_FORWARDS.V_DAY_COUNT_IND,STG_FORWARDS.V_HOLIDAY_ROLL_CONVENTION_CD,STG_FORWARDS.V_MARGIN_AGREEMENT_CD,STG_FORWARDS.V_OTHER_CCY_CODE,STG_FORWARDS.V_UNDERLYING_CCY_CODE,STG_UNDERLYING_EXPOSURES.F_EQUITY_TRADED_FLAG FROM STG_FORWARDS INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = STG_FORWARDS.FIC_MIS_DATE AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_FORWARDS.F_CAPITAL_CHARGE_EXCLUSION, 'N') <> 'Y' AND COALESCE(STG_FORWARDS.F_CLOSED_IND, 'N') <> 'Y' INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON STG_FORWARDS.V_CONTRACT_CODE = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE LEFT JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.N_DATE_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' AND FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG = 'N' LEFT JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_EXP' INNER JOIN FCT_ENTITY_INFO ON STG_FORWARDS.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_FORWARDS.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT JOIN ( SELECT STG_UNDERLYING_DTL.V_CONTRACT_INSTRUMENT_CODE ,MAX(COALESCE(DIM_INSTRUMENT_CONTRACT_ULY.D_MATURITY_DATE, TO_DATE('19000101', 'YYYYMMDD'))) D_MATURITY_DATE ,MIN(COALESCE(DIM_INSTRUMENT_CONTRACT_ULY.D_EFFECTIVE_DATE, TO_DATE('99991231', 'YYYYMMDD'))) D_EFFECTIVE_DATE FROM STG_UNDERLYING_DTL LEFT JOIN DIM_INSTRUMENT_CONTRACT DIM_INSTRUMENT_CONTRACT_ULY ON STG_UNDERLYING_DTL.V_INSTRUMENT_CODE = DIM_INSTRUMENT_CONTRACT_ULY.V_INSTRUMENT_CODE LEFT JOIN DIM_BANK_INSTRUMENT_TYPE ON