OIN DIM_PARTY DIM_PARTY_CM ON STG_FORWARDS.V_CLEARING_MEMBER_CODE = DIM_PARTY_CM.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_CM.D_RECORD_START_DATE AND DIM_PARTY_CM.D_RECORD_END_DATE LEFT JOIN DIM_PARTY ON STG_FORWARDS.V_CUST_REF_CODE = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT JOIN DIM_PRODUCT ON STG_FORWARDS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT JOIN DIM_GAAP ON STG_FORWARDS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT JOIN DIM_COUNTRY ON STG_FORWARDS.V_COUNTRY_CODE = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = COALESCE(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT JOIN DIM_NETTING_AGREEMENT ON STG_FORWARDS.V_NETTING_AGREEMENT_CODE = DIM_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_NETTING_AGREEMENT.D_RECORD_START_DATE AND DIM_NETTING_AGREEMENT.D_RECORD_END_DATE LEFT JOIN DIM_EXPOSURE_UNDERLYING_TYPE ON STG_FORWARDS.V_UNDERLYING_TYPE_CODE = DIM_EXPOSURE_UNDERLYING_TYPE.V_UNDERLYING_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_UNDERLYING_TYPE.D_RECORD_START_DATE AND DIM_EXPOSURE_UNDERLYING_TYPE.D_RECORD_END_DATE INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_A