STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN DIM_HOLDING_TYPE ON DIM_HOLDING_TYPE.V_HOLDING_TYPE = STG_FORWARDS.V_HOLDING_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HOLDING_TYPE.D_RECORD_START_DATE AND DIM_HOLDING_TYPE.D_RECORD_END_DATE LEFT JOIN STG_UNDERLYING_EXPOSURES ON STG_FORWARDS.V_CONTRACT_CODE = STG_UNDERLYING_EXPOSURES.V_PARENT_EXPOSURE_ID AND STG_FORWARDS.V_GAAP_CODE = STG_UNDERLYING_EXPOSURES.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') = STG_UNDERLYING_EXPOSURES.FIC_MIS_DATE LEFT JOIN DIM_UNDERLYING ON STG_FORWARDS.V_UNDERLYING_INSTRUMENT_CD = DIM_UNDERLYING.V_UNDERLYING_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_UNDERLYING.D_RECORD_START_DATE AND DIM_UNDERLYING.D_RECORD_END_DATE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_FORWARDS.V_CCY_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT JOIN DIM_EXPOSURE_SENIORITY ON DIM_EXPOSURE_SENIORITY.V_SENIORITY_CODE = STG_FORWARDS.V_SENIORITY_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_SENIORITY.D_RECORD_START_DATE AND DIM_EXPOSURE_SENIORITY.D_RECORD_END_DATE LEFT JOIN FSI_SENIORITY_RECLASSIFICATION ON FSI_SENIORITY_RECLASSIFICATION.N_SENIORITY = DIM_EXPOSURE_SENIORITY.N_EXP_SENIORITY AND FSI_SENIORITY_RECLASSIFICATION.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_SENIORITY_RECLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN DIM_EXPOSURE DIM_EXPOSURE_FIDUCIARY ON DIM_EXPOSURE_FIDUCIARY.V_EXPOSURE_ID = STG_FORWARDS.V_PARENT_FIDUCIARY_ACCT_NUMBER AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE_FIDUCIARY.D_RECORD_START_DATE AND DIM_EXPOSURE_FIDUCIARY.D_RECORD_END_DATE LEFT JOIN DIM_NETTING_AGREEMENT DUMMY_NETTING_AGREEMENT ON DUMMY_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE = 'DUMMY_NA_' || STG_FORWARDS.V_CONTRACT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DUMMY_NETTING_AGREEMENT.D_RECORD_START_DATE AND DUMMY_NETTING_AGREEMENT.D_RECORD_END_DATE LEFT JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT JOIN DIM_BANK_INSTRUMENT_TYPE ON DIM_BANK_INSTRUMENT_TYPE.V_BANK_INSTR_TYPE_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTR_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BANK_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_BANK_INSTRUMENT_TYPE.D_RECORD_END_DATE LEFT JOIN FSI_INSTR_TYPE_CLASSIFICATION ON DIM_BANK_INSTRUMENT_TYPE.N_BANK_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_BANK_INSTR_TYPE_SKEY AND FSI_INSTR_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_INSTR_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN FSI_INSTR_VALUATION_DETAILS ON FSI_INSTR_VALUATION_DETAILS.V_INSTRUMENT_CODE = STG_FORWARDS.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN FSI_INSTR_VALUATION_DETAILS.D_RECORD_START_DATE AND FSI_INSTR_VALUATION_DETAILS.D_RECORD_END_DATE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION C_FSI_CAP_CURRENCY_CONVERSION ON C_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = C_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND C_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_INSTR_VALUATION_DETAILS.V_CCY_CODE LEFT JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_REG ON DIM_ORG_STRUCTURE_REG.V_PARTY_ID = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_REG.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_REG.D_RECORD_END_DATE LEFT JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN FSI_REG_INDUSTRY_RECLASS ON FSI_REG_INDUSTRY_RECLASS.N_D_CUST_INDUSTRY_SKEY = DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY AND FSI_REG_INDUSTRY_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_INDUSTRY_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY LEFT JOIN FSI_INSTR_TYPE_ULY_TYPE_RECLS ON FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_INSTR_TYPE_ULY_TYPE_RECLS.N_INSTR_TYPE_SKEY = FSI_INSTR_TYPE_CLASSIFICATION.N_STD_INSTR_TYPE_SKEY WHERE 1=1 AND 1=1 AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = STG_FORWARDS.V_CONTRACT_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = STG_FORWARDS.FIC_MIS_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = STG_FORWARDS.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_FORWARDS.N_LOAD_RUN_ID ) LOG ERRORS INTO FSI_CAP_DERIVATIVES$ ('1776768407875_62962028_20260331_1_Job_23ea443aaa8641e9b9827bb08ec237da') REJECT LIMIT UNLIMITED;

